const now = new Date();
const month = now.getUTCMonth() + 1;
const year = now.getUTCFullYear();

let quarter;
if (month >= 1 && month <= 3) {
  quarter = 1;
} else if (month >= 4 && month <= 6) {
  quarter = 2;
} else if (month >= 7 && month <= 9) {
  quarter = 3;
} else {
  quarter = 4;
}

const quarterLabel = `${year}-Q${quarter}`;

return [{ json: { quarter: quarterLabel, year, quarterNumber: quarter } }];

const landscapeItems = $('Get Landscape Data').all();
const briefItems = $('Get Recent Briefs').all();
const quarterInfo = $('Compute Quarter').first();

const userId = landscapeItems.length > 0
  ? $('Get Users With Landscape').first().json.user_id
  : null;

if (!userId) {
  return [];
}

const quarter = quarterInfo.json.quarter;
const landscape = landscapeItems.map(i => i.json);
const briefs = briefItems.map(i => i.json);

const totalCompanies = landscape.length;
const freeTierCount = landscape.filter(c => c.has_free_tier).length;
const enterpriseCount = landscape.filter(c => c.has_enterprise).length;
const valueMetrics = [...new Set(landscape.map(c => c.value_metric).filter(Boolean))];
const tierCounts = landscape.map(c => c.plan_count).filter(Boolean);
const avgTiers = tierCounts.length > 0 ? (tierCounts.reduce((a, b) => a + b, 0) / tierCounts.length).toFixed(1) : 0;
const gatingStrategies = [...new Set(landscape.map(c => c.gating_strategy).filter(Boolean))];

// --- STRENGTHS ---
const strengths = [];

// Unique value metrics
const metricCounts = {};
landscape.forEach(c => {
  if (c.value_metric) {
    metricCounts[c.value_metric] = (metricCounts[c.value_metric] || 0) + 1;
  }
});
for (const [metric, count] of Object.entries(metricCounts)) {
  if (count === 1) {
    const company = landscape.find(c => c.value_metric === metric);
    strengths.push({
      claim: `${company.company_name} has a unique value metric: ${metric}`,
      evidence_count: 1
    });
  }
}

// Only one with free tier
if (freeTierCount === 1) {
  const company = landscape.find(c => c.has_free_tier);
  strengths.push({
    claim: `${company.company_name} is the only competitor offering a free tier`,
    evidence_count: totalCompanies
  });
}

// Most tiers
const maxTiers = Math.max(...tierCounts, 0);
const maxTierCompanies = landscape.filter(c => c.plan_count === maxTiers);
if (maxTierCompanies.length === 1 && maxTiers > 0) {
  strengths.push({
    claim: `${maxTierCompanies[0].company_name} offers the most pricing tiers (${maxTiers})`,
    evidence_count: 1
  });
}

// Unique gating strategy
const gatingCounts = {};
landscape.forEach(c => {
  if (c.gating_strategy) {
    gatingCounts[c.gating_strategy] = (gatingCounts[c.gating_strategy] || 0) + 1;
  }
});
for (const [strategy, count] of Object.entries(gatingCounts)) {
  if (count === 1) {
    const company = landscape.find(c => c.gating_strategy === strategy);
    strengths.push({
      claim: `${company.company_name} has a unique gating strategy: ${strategy}`,
      evidence_count: 1
    });
  }
}

// --- VULNERABILITIES ---
const vulnerabilities = [];

// No free tier when most competitors have one
if (freeTierCount > totalCompanies / 2) {
  const noFree = landscape.filter(c => !c.has_free_tier);
  noFree.forEach(c => {
    vulnerabilities.push({
      gap: 'No free tier while majority of competitors offer one',
      competitor: c.company_name,
      severity: freeTierCount >= totalCompanies * 0.75 ? 'high' : 'medium'
    });
  });
}

// No enterprise when competitors have it
if (enterpriseCount > totalCompanies / 2) {
  const noEnterprise = landscape.filter(c => !c.has_enterprise);
  noEnterprise.forEach(c => {
    vulnerabilities.push({
      gap: 'No enterprise tier while majority of competitors offer one',
      competitor: c.company_name,
      severity: enterpriseCount >= totalCompanies * 0.75 ? 'high' : 'medium'
    });
  });
}

// Fewer tiers than average
landscape.forEach(c => {
  if (c.plan_count && c.plan_count < avgTiers * 0.7) {
    vulnerabilities.push({
      gap: `Only ${c.plan_count} tiers vs. landscape average of ${avgTiers}`,
      competitor: c.company_name,
      severity: c.plan_count <= 1 ? 'high' : 'medium'
    });
  }
});

// --- OPPORTUNITIES ---
const opportunities = [];

// No one offering usage-based
const usageBased = landscape.filter(c =>
  c.value_metric && c.value_metric.toLowerCase().includes('usage')
);
if (usageBased.length === 0 && totalCompanies > 0) {
  opportunities.push({
    position: 'Usage-based pricing model',
    rationale: 'No competitor currently offers usage-based pricing, creating an unoccupied position'
  });
}

// Gap in tier count
const tierSet = new Set(tierCounts);
for (let i = Math.min(...tierCounts); i <= Math.max(...tierCounts); i++) {
  if (!tierSet.has(i) && i > 0) {
    opportunities.push({
      position: `${i}-tier pricing structure`,
      rationale: `No competitor occupies the ${i}-tier position, a potential gap in the market`
    });
  }
}

// No hybrid model
const hybridGating = landscape.filter(c =>
  c.gating_strategy && c.gating_strategy.toLowerCase().includes('hybrid')
);
if (hybridGating.length === 0 && totalCompanies > 0) {
  opportunities.push({
    position: 'Hybrid gating model (feature + usage)',
    rationale: 'No competitor uses a hybrid gating strategy, combining feature and usage gates'
  });
}

// --- THREATS ---
const threats = [];

// Convergence patterns from briefs
const changeTypeCounts = {};
briefs.forEach(b => {
  if (b.change_type) {
    if (!changeTypeCounts[b.change_type]) {
      changeTypeCounts[b.change_type] = [];
    }
    changeTypeCounts[b.change_type].push(b.company_name);
  }
});

for (const [changeType, companies] of Object.entries(changeTypeCounts)) {
  const uniqueCompanies = [...new Set(companies)];
  if (uniqueCompanies.length >= 2) {
    threats.push({
      threat: `Multiple competitors making ${changeType} changes`,
      competitors: uniqueCompanies.join(', '),
      urgency: uniqueCompanies.length >= 3 ? 'high' : 'medium'
    });
  }
}

// Multiple competitors moving to same value metric
for (const [metric, count] of Object.entries(metricCounts)) {
  if (count >= 2) {
    const companiesWithMetric = landscape.filter(c => c.value_metric === metric).map(c => c.company_name);
    threats.push({
      threat: `Convergence toward ${metric} as value metric`,
      competitors: companiesWithMetric.join(', '),
      urgency: count >= 3 ? 'high' : 'medium'
    });
  }
}

// Multiple adding same tier type (free or enterprise)
if (freeTierCount >= 3) {
  const freeCompanies = landscape.filter(c => c.has_free_tier).map(c => c.company_name);
  threats.push({
    threat: 'Free tier becoming table stakes as most competitors now offer one',
    competitors: freeCompanies.join(', '),
    urgency: 'high'
  });
}
if (enterpriseCount >= 3) {
  const entCompanies = landscape.filter(c => c.has_enterprise).map(c => c.company_name);
  threats.push({
    threat: 'Enterprise tier becoming table stakes as most competitors now offer one',
    competitors: entCompanies.join(', '),
    urgency: 'high'
  });
}

// --- BUILD MARKDOWN REPORT ---
const title = `Packaging Audit \u2014 ${quarter}`;

let contentMd = `# ${title}\n\n`;
contentMd += `**Period:** Last 90 days | **Companies tracked:** ${totalCompanies} | **Briefs analyzed:** ${briefs.length}\n\n`;

contentMd += `## Strengths\n\n`;
if (strengths.length === 0) {
  contentMd += `_No distinct packaging strengths identified this quarter._\n\n`;
} else {
  strengths.forEach(s => {
    contentMd += `- **${s.claim}** (evidence count: ${s.evidence_count})\n`;
  });
  contentMd += `\n`;
}

contentMd += `## Vulnerabilities\n\n`;
if (vulnerabilities.length === 0) {
  contentMd += `_No packaging vulnerabilities identified this quarter._\n\n`;
} else {
  vulnerabilities.forEach(v => {
    contentMd += `- **${v.competitor}**: ${v.gap} (severity: ${v.severity})\n`;
  });
  contentMd += `\n`;
}

contentMd += `## Opportunities\n\n`;
if (opportunities.length === 0) {
  contentMd += `_No unoccupied positions identified this quarter._\n\n`;
} else {
  opportunities.forEach(o => {
    contentMd += `- **${o.position}**: ${o.rationale}\n`;
  });
  contentMd += `\n`;
}

contentMd += `## Threats\n\n`;
if (threats.length === 0) {
  contentMd += `_No convergence threats identified this quarter._\n\n`;
} else {
  threats.forEach(t => {
    contentMd += `- **${t.threat}** \u2014 ${t.competitors} (urgency: ${t.urgency})\n`;
  });
  contentMd += `\n`;
}

// --- BUILD CONTENT JSON ---
const contentJson = JSON.stringify({
  total_companies: totalCompanies,
  free_tier_count: freeTierCount,
  enterprise_count: enterpriseCount,
  avg_tiers: parseFloat(avgTiers),
  value_metrics: valueMetrics,
  gating_strategies: gatingStrategies,
  briefs_analyzed: briefs.length,
  strengths_count: strengths.length,
  vulnerabilities_count: vulnerabilities.length,
  opportunities_count: opportunities.length,
  threats_count: threats.length
});

return [{
  json: {
    user_id: userId,
    quarter,
    title,
    content_json: contentJson,
    content_md: contentMd,
    strengths: JSON.stringify(strengths),
    vulnerabilities: JSON.stringify(vulnerabilities),
    opportunities: JSON.stringify(opportunities),
    threats: JSON.stringify(threats)
  }
}];
